import (
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Initialize the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 2. Initialize the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 3. Create a pipe to connect stdout of aliyun to stdin of jq
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	jqCmd.Stdin = pipe

	// 4. Prepare to capture the output from jq
	var outputBuffer strings.Builder
	jqCmd.Stdout = &outputBuffer

	// 5. Open the output file for writing
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// 6. Use MultiWriter to write to both the buffer (for return) and the file
	multiWriter := io.MultiWriter(&outputBuffer, file)
	jqCmd.Stdout = multiWriter

	// 7. Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// 8. Start and wait for the jq command
	// Note: jq waits for input from the pipe, which comes from aliyunCmd
	if err := jqCmd.Run(); err != nil {
		return "", fmt.Errorf("failed to run jq command: %w", err)
	}

	// 9. Wait for the aliyun command to finish
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	return outputBuffer.String(), nil
}

