package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation to ensure parameters do not contain shell injection characters.
	// This prevents command injection if the inputs were to be used in a shell context.
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// 1. Execute the aliyun command to get SLB details.
	// Using exec.Command directly with arguments prevents shell injection.
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Capture the output of the aliyun command to pipe into jq
	var aliyunOut bytes.Buffer
	aliyunCmd.Stdout = &aliyunOut

	// Run the aliyun command
	if err := aliyunCmd.Run(); err != nil {
		return "", fmt.Errorf("failed to execute aliyun command: %w", err)
	}

	// 2. Execute jq to process the JSON output.
	// We use the captured output from the previous command as input to jq.
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = &aliyunOut

	// 3. Set up file output for the jq command.
	// Using exec.Command directly with arguments prevents shell injection for the file path.
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	jqCmd.Stdout = outFile

	// Capture stderr from jq to return in case of errors
	var jqErr bytes.Buffer
	jqCmd.Stderr = &jqErr

	// Run the jq command
	if err := jqCmd.Run(); err != nil {
		return jqErr.String(), fmt.Errorf("failed to execute jq command: %w", err)
	}

	// Return the processed content (what was written to the file) as a string
	return aliyunOut.String(), nil
}

