package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun command to query SLB information,
// formats the output using jq, and saves it to the specified file.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Step 1: Execute the aliyun command to get SLB details
	// We use exec.LookPath to ensure the command exists in the PATH
	aliyunPath, err := exec.LookPath("aliyun")
	if err != nil {
		return "", fmt.Errorf("aliyun command not found: %w", err)
	}

	jqPath, err := exec.LookPath("jq")
	if err != nil {
		return "", fmt.Errorf("jq command not found: %w", err)
	}

	// Create the command for aliyun
	cmdAliyun := exec.Command(aliyunPath, "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the command for jq
	// We set the filter to extract the array items
	cmdJq := exec.Command(jqPath, ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect the stdout of aliyun to the stdin of jq
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	cmdJq.Stdin = pipe

	// Capture the stdout of jq to write to the file and return as string
	var outBuf bytes.Buffer
	cmdJq.Stdout = &outBuf

	// Capture stderr for both commands to provide better error messages
	var errBuf bytes.Buffer
	cmdAliyun.Stderr = &errBuf
	cmdJq.Stderr = &errBuf

	// Start the aliyun command
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the jq command
	if err := cmdJq.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun to finish
	if err := cmdAliyun.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, errBuf.String())
	}

	// Wait for jq to finish
	if err := cmdJq.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, errBuf.String())
	}

	// Write the formatted output to the specified file
	if err := os.WriteFile(outputFile, outBuf.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return outBuf.String(), nil
}

func main() {
	// Example usage
	name := "my-slb-name"
	file := "output.json"

	result, err := QuerySLBAndExport(name, file)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Successfully exported SLB info to %s\n", file)
	fmt.Printf("Content:\n%s\n", result)
}

