package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun command to query SLB information,
// formats the output using jq, and saves it to the specified file.
// It returns the combined stdout/stderr of the pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Step 1: Create the command for 'aliyun slb DescribeLoadBalancers'
	// We use StdoutPipe to connect the output to the next command.
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Step 2: Create the command for 'jq'
	// We use StdinPipe to read from the previous command's output.
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect the two commands
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}

	jqCmd.Stdin = pipe

	// Prepare a buffer to capture the output of the jq command
	var out bytes.Buffer
	jqCmd.Stdout = &out

	// Also capture stderr from both commands to provide meaningful error messages
	var stderrCombined bytes.Buffer
	aliyunCmd.Stderr = &stderrCombined
	jqCmd.Stderr = &stderrCombined

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the jq command
	// Note: We call Run on jqCmd which waits for it to finish.
	// Since jqCmd.Stdin is reading from the pipe connected to aliyunCmd,
	// this will implicitly wait for aliyunCmd to finish writing as well.
	if err := jqCmd.Run(); err != nil {
		return "", fmt.Errorf("failed to run jq command: %w (stderr: %s)", err, stderrCombined.String())
	}

	// Wait for the aliyun command to fully exit and release resources.
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command error: %w (stderr: %s)", err, stderrCombined.String())
	}

	// Step 3: Write the formatted output to the specified file
	if err := os.WriteFile(outputFile, out.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file %s: %w", outputFile, err)
	}

	return out.String(), nil
}

func main() {
	// Example usage
	name := "my-slb-instance"
	file := "output.json"

	result, err := QuerySLBAndExport(name, file)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Successfully queried SLB and exported to %s.\n", file)
	fmt.Printf("Content:\n%s\n", result)
}

