)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation to prevent obvious shell injection
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Setup the pipeline: aliyun | jq > file
	// Get jq's stdin pipe
	jqIn, err := jqCmd.StdinPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get jq stdin pipe: %w", err)
	}

	// Set jq's stdout to the file
	jqCmd.Stdout = outFile

	// Start the jq command
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Run the aliyun command and pipe output to jq
	// We capture aliyun's output to return it as the function result
	var aliyunOutput strings.Builder
	// Use MultiWriter to write to both the jq pipe and our buffer
	multiWriter := io.MultiWriter(jqIn, &aliyunOutput)

	aliyunCmd.Stdout = multiWriter

	// Run aliyun
	if err := aliyunCmd.Run(); err != nil {
		return aliyunOutput.String(), fmt.Errorf("aliyun command failed: %w", err)
	}

	// Close aliyun's output (which is jq's input) to signal EOF to jq
	if err := jqIn.Close(); err != nil {
		return aliyunOutput.String(), fmt.Errorf("failed to close jq stdin: %w", err)
	}

	// Wait for jq to finish
	if err := jqCmd.Wait(); err != nil {
		return aliyunOutput.String(), fmt.Errorf("jq command failed: %w", err)
	}

	return aliyunOutput.String(), nil
}

