	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %v", err)
	}

	jqCmd.Stdin = pipe

	// 4. Prepare to capture the output from jqCmd
	// We need to write this to the outputFile, but also capture it for the return value
	var outBuf bytes.Buffer
	multiWriter := io.MultiWriter(&outBuf)

	jqCmd.Stdout = multiWriter

	// Also capture stderr for both commands to provide meaningful error messages
	var errBuf bytes.Buffer
	aliyunCmd.Stderr = &errBuf
	jqCmd.Stderr = &errBuf

	// 5. Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %v", err)
	}

	// 6. Start and wait for the jq command
	// Note: jqCmd.Start() must be called after aliyunCmd.Start() to avoid deadlock if pipes fill up,
	// but typically we start the reader first. However, since jq reads from the pipe,
	// we start aliyun (writer) then jq (reader).
	// Wait waits for the command to exit and waits for any copying from stdin or copying to stdout to complete.
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %v", err)
	}

	// Wait for aliyun to finish
	if err := aliyunCmd.Wait(); err != nil {
		// If aliyun fails, jq might fail too, but we prioritize the first error
		return fmt.Sprintf("Stderr: %s", errBuf.String()), fmt.Errorf("aliyun command failed: %v", err)
	}

	// Wait for jq to finish
	if err := jqCmd.Wait(); err != nil {
		return fmt.Sprintf("Stderr: %s", errBuf.String()), fmt.Errorf("jq command failed: %v", err)
	}

	// 7. Write the formatted output to the specified file
	if err := os.WriteFile(outputFile, outBuf.Bytes(), 0644); err != nil {
		return outBuf.String(), fmt.Errorf("failed to write output file: %v", err)
	}

	return outBuf.String(), nil
}

