package main

import (
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 2. Create the jq command
	// jq reads from stdin and writes JSON to stdout
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 3. Create the file for output
	// Use os.O_CREATE | os.O_TRUNC | os.O_WRONLY to create or overwrite the file
	file, err := os.OpenFile(outputFile, os.O_CREATE|os.O_TRUNC|os.O_WRONLY, 0644)
	if err != nil {
		return "", fmt.Errorf("failed to open output file: %w", err)
	}
	defer file.Close()

	// 4. Setup the pipeline: aliyun -> jq -> file
	// Get jq's stdin pipe
	jqStdin, err := jqCmd.StdinPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get jq stdin pipe: %w", err)
	}

	// Set jq's stdout to the file
	jqCmd.Stdout = file

	// Capture jq's stderr to include in potential error messages
	var jqStderr bytes.Buffer
	jqCmd.Stderr = &jqStderr

	// Start the jq command (it will wait for input on stdin)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Run the aliyun command and pipe output to jq's stdin
	if err := aliyunCmd.Run(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Close jq's stdin to signal EOF
	if err := jqStdin.Close(); err != nil {
		return "", fmt.Errorf("failed to close jq stdin: %w", err)
	}

	// Wait for jq to finish processing
	if err := jqCmd.Wait(); err != nil {
		return jqStderr.String(), fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr.String())
	}

	// Return the path of the generated file as the result string
	return outputFile, nil
}

