	// aliyunCmd.Stdout -> jqCmd.Stdin
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun: %v", err)
	}
	jqCmd.Stdin = pipe

	// Step 4: Prepare to capture the output from jqCmd to write to the file
	// We use a buffer to capture the output for the return value
	var outBuf bytes.Buffer
	// Create a MultiWriter so we can write to both the file and the buffer
	var fileWriter *os.File
	if fileWriter, err = os.Create(outputFile); err != nil {
		return "", fmt.Errorf("failed to create output file %s: %v", outputFile, err)
	}
	defer fileWriter.Close()

	multiWriter := io.MultiWriter(fileWriter, &outBuf)
	jqCmd.Stdout = multiWriter

	// Also capture stderr from both commands to a single buffer to return in case of error
	var errBuf bytes.Buffer
	aliyunCmd.Stderr = &errBuf
	jqCmd.Stderr = &errBuf

	// Step 5: Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %v", err)
	}

