package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect the stdout of aliyun to the stdin of jq
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	jqCmd.Stdin = pipe

	// Capture the output from jq to return it
	var jqOutputBuf bytes.Buffer
	jqCmd.Stdout = &jqOutputBuf

	// Capture stderr from both commands into a single buffer for error reporting
	var stderrBuf bytes.Buffer
	aliyunCmd.Stderr = &stderrBuf
	jqCmd.Stderr = &stderrBuf

	// Open the output file for writing
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// Use a MultiWriter to write jq output to both the buffer (for return) and the file
	multiWriter := io.MultiWriter(&jqOutputBuf, file)
	jqCmd.Stdout = multiWriter

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the jq command.
	// Note: jq waits for input from the pipe connected to aliyunCmd.
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun to finish sending data
	if err := aliyunCmd.Wait(); err != nil {
		return stderrBuf.String(), fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for jq to finish processing
	if err := jqCmd.Wait(); err != nil {
		return stderrBuf.String(), fmt.Errorf("jq command failed: %w", err)
	}

	return jqOutputBuf.String(), nil
}

